export default function App() {
  // Try to recover a previous session before initial render so the UI
  // shows the data immediately (no flicker). All persisted UI state
  // (filters, sort, active tab, selected event) is restored alongside
  // the data so the user lands exactly where they left off.
  const initial = typeof window !== "undefined" ? loadFromStorage() : null;
  const [rawEvents, setRawEvents] = useState(initial?.rawEvents || []);
  const [runMetadata, setRunMetadata] = useState(initial?.runMetadata || null);
  const [ab, setAb] = useState(initial?.ab || null);
  const [metadata, setMetadata] = useState(initial?.metadata || null);
  const [plateMap, setPlateMap] = useState(initial?.plateMap || null);
  const [tab, setTab] = useState(initial?.tab || "overview");
  const [selId, setSelId] = useState(
    initial?.selId !== undefined ? initial.selId : null,
  );
  const [focusPlate, setFocusPlate] = useState(null);
  const [filter, setFilter] = useState(() => {
    // Migrate legacy boolean fields (hideRelated / adjacentOnly) to the
    // tri-state strings while preserving the user's last selection.
    // Verdict went from a single string ("all" | "pending" | ...) to a
    // multi-select array; promote the old shape if found.
    const f = initial?.filter || {};
    const ALL_VERDICTS = ["pending", "true_positive", "false_positive", "uncertain"];
    let verdicts;
    if (Array.isArray(f.verdicts)) verdicts = f.verdicts;
    else if (f.verdict && f.verdict !== "all") verdicts = [f.verdict];
    else verdicts = ALL_VERDICTS;
    return {
      q: f.q ?? "",
      minScore: f.minScore ?? 0,
      minRate: f.minRate ?? 0,
      minIntroduced: f.minIntroduced ?? 0,
      verdicts,
      subject: f.subject ?? (f.hideRelated ? "different" : "any"),
      group: f.group ?? "any",
      adjacent: f.adjacent ?? (f.adjacentOnly ? "adjacent" : "any"),
    };
  });
  const [sort, setSort] = useState(initial?.sort || { by: "score", dir: "desc" });
  const [err, setErr] = useState(null);
  const eventFileRef = useRef(null);
  const abFileRef = useRef(null);

  /* Save indicator: shows a discrete "Saved" pill briefly after each
     auto-save. Set to a timestamp on save; the indicator fades out via
     a separate timeout. */
  const [savedAt, setSavedAt] = useState(null);

  /* Tutorial state — two pieces:
     - welcomeOpen: the first-visit popup that asks "Take the tour or
       skip?". Shown only when there's no prior session AND the user has
       never seen the tutorial.
     - tutorialOpen: the actual side-panel walkthrough. Set to true
       either by clicking "Take the tour" in the welcome popup, or by
       clicking "Restart tour" in the Help tab. */
  const [welcomeOpen, setWelcomeOpen] = useState(() => {
    if (typeof window === "undefined") return false;
    return !initial && !tutorialWasSeen();
  });
  const [tutorialOpen, setTutorialOpen] = useState(false);

  const tutorialSteps = useMemo(
    () => [
      {
        title: "Welcome — let's load the demo",
        body:
          "We'll walk through the workflow using the bundled Lou et al. 2023 P3 dataset.\n\n" +
          "It includes contamination events, abundance table, sample metadata and plate map — everything needed to demonstrate the tool.\n\n" +
          "Click below to load it. The Next button unlocks once the data is in.",
        action: "tabOverviewAndLoadDemo",
        requires: "data",
      },
      {
        title: "Overview — the big picture",
        body:
          "First stop: the Overview tab.\n\n" +
          "It shows the run parameters from CroCoDeEL, total event counts, and the highest-rate / highest-probability events. Always start here to understand what you're dealing with.",
        action: "tabOverview",
        highlight: '[data-tutorial="tab-overview"]',
      },
      {
        title: "Events table — sort and filter",
        body:
          "The Events table lists every flagged contamination event.\n\n" +
          "Filter by minimum probability, minimum rate, or hide longitudinal pairs (same subject). Sort any column. Click a row to inspect that event in Guided validation.",
        action: "tabTable",
        highlight: '[data-tutorial="tab-table"]',
      },
      {
        title: "Scatterplots — visual evidence",
        body:
          "Each event becomes a scatterplot of source vs target abundances.\n\n" +
          "Points on the y=x diagonal mean the species are equally abundant in both samples — a clean contamination signature. Points above the line mean the species is more abundant in the target than the source, which weakens the case.",
        action: "tabScatter",
        highlight: '[data-tutorial="tab-scatter"]',
      },
      {
        title: "Network — see the contamination web",
        body:
          "The Network tab plots all events as a directed graph: nodes are samples, edges are contamination events.\n\n" +
          "Edge thickness scales with rate. Cascade samples (both source and target in different events) appear in salmon. Useful to spot systemic patterns or single sample acting as a hub.",
        action: "tabNetwork",
        highlight: '[data-tutorial="tab-network"]',
      },
      {
        title: "Plate map — three views",
        body:
          "The Plate map tab opens with three sub-modes you can switch between:\n\n" +
          "• Overview — thumbnails of every plate at once\n" +
          "• Inspect — one plate full-size with contamination arrows\n" +
          "• Edit — drag samples between wells to fix the map (we'll skip this for now — it's there when you need it)\n\n" +
          "Let's look at Inspect mode.",
        action: "tabPlate",
        highlight: '[data-tutorial="tab-plate"]',
      },
      {
        title: "Plate Inspect — well-to-well leakage",
        body:
          "Inspect mode draws an arrow from source to contaminated well for every event involving the current plate.\n\n" +
          "Arrow color = the well-to-well distance: red for adjacent wells (Δ = 1, very suspicious), orange for Δ = 2, gray for further apart, violet for cascade events. Arrow thickness scales with the contamination rate.\n\n" +
          "Adjacent wells with high rates almost always indicate liquid carry-over during pipetting or extraction.",
        action: "tabPlateInspect",
        highlight: '[data-tutorial="plate-inspect"]',
      },
      {
        title: "Filter what you see on the plate",
        body:
          "Use the filters in Inspect mode to focus your investigation:\n\n" +
          "• Show only this plate / inter-plate / adjacent (Δ ≤ 1)\n" +
          "• Hide arrows entirely if the plate is too crowded\n" +
          "• Hide same-subject events to remove longitudinal noise\n\n" +
          "Hovering a well also highlights every event touching it.",
        highlight: '[data-tutorial="plate-controls"]',
      },
      {
        title: "Guided validation — make verdicts",
        body:
          "This is where you decide for each event: True positive (real contamination), False positive (biological signal), or Uncertain.\n\n" +
          "You see the scatterplot, six diagnostic criteria, plate position, and full sample context — everything in one screen.",
        action: "tabValidate",
        highlight: '[data-tutorial="tab-validate"]',
      },
      {
        title: "Keyboard shortcuts speed up curation",
        body:
          "Press T (True positive), F (False positive) or U (Uncertain) to validate the current event.\n\n" +
          "Then ← / → jump to the previous/next pending event automatically.\n\n" +
          "Press ? in the app to see all shortcuts.",
        highlight: '[data-tutorial="verdict-buttons"]',
      },
      {
        title: "Bulk actions for obvious cases",
        body:
          "On longitudinal datasets, two heuristics handle most events automatically:\n\n" +
          "• Same-subject pairs (longitudinal) → almost always false positives. One click classifies them all with explanatory notes.\n\n" +
          "• Contamination flowing into a negative control → almost always real well-to-well leakage. One click classifies them as true positives.",
        highlight: '[data-tutorial="bulk-actions"]',
      },
      {
        title: "Export your curated report",
        body:
          "When done, the Export tab produces a curated TSV (true positives only, or everything except false positives) and a JSON audit trail with every verdict, note and metadata context.",
        action: "tabExport",
        highlight: '[data-tutorial="tab-export"]',
      },
      {
        title: "Learn the patterns",
        body:
          "One last stop: the Learn tab is a reference for reading scatterplots, built around the 12 canonical cases from the Goulet et al. 2025 paper.\n\n" +
          "Curation isn't just about clicking buttons — it's about training your eye. We'll walk through the three categories you'll encounter.",
        action: "tabLearn",
        highlight: '[data-tutorial="tab-learn"]',
      },
      {
        title: "True positives — real contamination",
        body:
          "Four examples (A-D) of contamination CroCoDeEL flags AND humans confirm.\n\n" +
          "The shared signature: a clear linear cluster parallel to y = x, with the dashed salmon line marking exactly where the contamination signal sits. Rate is independent of how obvious the line is — even 0.49% (case B) can be unambiguous when the pattern is clean.",
        action: "tabLearn",
        highlight: '[data-tutorial="learn-tp"]',
      },
      {
        title: "False positives — flagged but biological",
        body:
          "CroCoDeEL flagged these but a curator decided they're biological similarity.\n\n" +
          "Cases F, G and H are stringency-dependent — strict curators might tag them Uncertain instead. The visual key: do the points actually hug the dashed salmon line? On a true positive yes, on a false positive no.",
        action: "tabLearn",
        highlight: '[data-tutorial="learn-fp"]',
      },
      {
        title: "False negatives — what CroCoDeEL misses",
        body:
          "Events humans identified but CroCoDeEL didn't flag. These won't appear in your events table by definition — knowing the patterns helps you decide whether to lower the probability cutoff at the CroCoDeEL stage to widen the search.\n\n" +
          "Case K (cascade contamination) is especially worth knowing: when two samples share a third common contamination source, the line is blurred and CroCoDeEL learned to reject it.",
        action: "tabLearn",
        highlight: '[data-tutorial="learn-fn"]',
      },
      {
        title: "You're ready!",
        body:
          "Your work is auto-saved to your browser as you go — close the tab and come back anytime.\n\n" +
          "The Learn tab is always there if you want to revisit the patterns. Need this whole tour again? Help tab → 'Restart guided tour'.\n\n" +
          "Click 'Got it!' to start exploring on your own.",
        action: "tabOverview",
      },
    ],
    [],
  );

  /** Apply the side-effect attached to a tutorial step. Called by the
      panel whenever a new step becomes active. */
  const handleTutorialAction = (action) => {
    switch (action) {
      case "tabOverviewAndLoadDemo":
        // Always go to Overview (it's where the welcome step belongs).
        // Trigger the demo load only if the session is empty — by the
        // time we get here the user has either started fresh or already
        // confirmed replacing their data via startTutorial().
        setTab("overview");
        if (rawEvents.length === 0 && !demoLoading) loadDemo();
        break;
      case "loadDemo":
        if (rawEvents.length === 0) loadDemo();
        break;
      case "tabOverview":
        setTab("overview");
        break;
      case "tabTable":
        setTab("table");
        break;
      case "tabScatter":
        setTab("scatter");
        break;
      case "tabNetwork":
        setTab("network");
        break;
      case "tabValidate":
        setTab("validate");
        break;
      case "tabPlate":
        setTab("plate");
        break;
      case "tabPlateInspect":
        setTab("plate");
        // Switch to Inspect sub-mode by clicking its button — that mode
        // state lives inside PlateTab and we don't want to refactor it
        // for this one-off animation.
        setTimeout(() => {
          document
            .querySelector('[data-tutorial="plate-mode-inspect"]')
            ?.click();
        }, 100);
        break;
      case "tabPlateEdit":
        setTab("plate");
        setTimeout(() => {
          document
            .querySelector('[data-tutorial="plate-mode-edit"]')
            ?.click();
        }, 100);
        break;
      case "tabExport":
        setTab("export");
        break;
      case "tabLearn":
        setTab("learn");
        break;
      default:
        break;
    }
  };

  /* Auto-save the full session to localStorage whenever any persisted
     state changes. Debounced to 200 ms so we don't hammer the disk
     when the user blasts through events with keyboard shortcuts. */
  useEffect(() => {
    if (rawEvents.length === 0) {
      // No data to save — actively clear storage so a previous session
      // doesn't linger after the user clears everything.
      clearStorage();
      setSavedAt(null);
      return undefined;
    }
    const handle = setTimeout(() => {
      const ok = saveToStorage({
        version: 1,
        savedAt: new Date().toISOString(),
        rawEvents,
        runMetadata,
        metadata,
        plateMap,
        ab,
        // UI state — keeps the user exactly where they left off
        tab,
        selId,
        filter,
        sort,
      });
      if (ok) setSavedAt(Date.now());
    }, 200);
    return () => clearTimeout(handle);
  }, [rawEvents, runMetadata, metadata, plateMap, ab, tab, selId, filter, sort]);

  /* When a CroCoDeEL run header carries explicit cutoffs, pre-set the
     events-table filters to those values. The user can still lower them
     manually if they want to inspect events the cutoff filtered out
     (though CroCoDeEL itself wouldn't have written them anyway). */
  useEffect(() => {
    const probCutoff = parseFloat(runMetadata?.probability_cutoff);
    const rateCutoff = parseFloat(runMetadata?.rate_cutoff);
    setFilter((f) => ({
      ...f,
      minScore:
        Number.isFinite(probCutoff) && probCutoff > 0 ? probCutoff : f.minScore,
      minRate:
        Number.isFinite(rateCutoff) && rateCutoff > 0 ? rateCutoff : f.minRate,
    }));
  }, [runMetadata]);

  /* ---- derived state ---- */
  /** Count of species with non-zero abundance per sample. Used to compute
      introducedPct (= introduced species / target's total species). */
  const targetSpeciesCounts = useMemo(() => {
    if (!ab) return null;
    const counts = {};
    for (const sample of ab.samples) {
      let n = 0;
      for (const sp of ab.species) {
        if ((ab.matrix[sp]?.[sample] || 0) > 0) n++;
      }
      counts[sample] = n;
    }
    return counts;
  }, [ab]);

  const events = useMemo(() => {
    const cascaded = detectCascades(rawEvents, ab);
    if (!targetSpeciesCounts) return cascaded;
    return cascaded.map((e) => {
      const total = targetSpeciesCounts[e.target];
      const pct =
        total > 0 && Array.isArray(e.introduced)
          ? (e.introduced.length / total) * 100
          : null;
      return { ...e, introducedPct: pct };
    });
  }, [rawEvents, ab, targetSpeciesCounts]);

  const allSamples = useMemo(() => {
    if (ab) return ab.samples;
    const s = new Set();
    rawEvents.forEach((e) => {
      s.add(e.source);
      s.add(e.target);
    });
    return Array.from(s).sort();
  }, [ab, rawEvents]);

  /** Sanity check — warn when event sample names don't match abundance columns */
  const sampleMismatches = useMemo(() => {
    if (!ab || rawEvents.length === 0) return null;
    const abSet = new Set(ab.samples);
    const abSetLC = new Set(ab.samples.map((s) => s.toLowerCase().trim()));
    const missing = new Set();
    const casediff = new Set();
    rawEvents.forEach((e) => {
      [e.source, e.target].forEach((name) => {
        if (!name) return;
        if (abSet.has(name)) return;
        if (abSetLC.has(String(name).toLowerCase().trim())) {
          casediff.add(name);
        } else {
          missing.add(name);
        }
      });
    });
    if (missing.size === 0 && casediff.size === 0) return null;
    return {
      missing: Array.from(missing).slice(0, 10),
      missingCount: missing.size,
      casediff: Array.from(casediff).slice(0, 5),
      casediffCount: casediff.size,
    };
  }, [ab, rawEvents]);

  const filtered = useMemo(() => {
    const q = filter.q.trim().toLowerCase();
    const minIntro = filter.minIntroduced || 0;
    let res = events.filter((e) => {
      if (e.score < filter.minScore) return false;
      if (e.rate < filter.minRate) return false;
      if (minIntro > 0) {
        if (e.introducedPct == null) return false;
        if (e.introducedPct < minIntro) return false;
      }
      if (filter.verdicts && filter.verdicts.length < 4) {
        if (!filter.verdicts.includes(e.verdict || "pending")) return false;
      }
      // Subject filter — events are "same subject" only when both samples
      // are annotated and share a subject_id (areRelated.kind === "subject").
      // Events with missing/unknown subjects are treated as "different" so
      // they pass the "different" filter.
      if (filter.subject && filter.subject !== "any") {
        const r = areRelated(metadata, e.source, e.target);
        const sameSubject = r?.related === true && r.kind === "subject";
        if (filter.subject === "same" && !sameSubject) return false;
        if (filter.subject === "different" && sameSubject) return false;
      }
      // Group filter — same logic on group_id.
      if (filter.group && filter.group !== "any") {
        const r = areRelated(metadata, e.source, e.target);
        const sameGroup = r?.related === true && r.kind === "group";
        if (filter.group === "same" && !sameGroup) return false;
        if (filter.group === "different" && sameGroup) return false;
      }
      if (filter.adjacent && filter.adjacent !== "any") {
        const pd = plateDistance(plateMap, e.source, e.target);
        const isAdjacent =
          pd && pd.samePlate && pd.distance != null && pd.distance <= 1;
        if (filter.adjacent === "adjacent" && !isAdjacent) return false;
        if (filter.adjacent === "non-adjacent" && isAdjacent) return false;
      }
      if (q) {
        // Search across sample IDs only (source and target). Case-
        // insensitive thanks to the toLowerCase on both sides.
        const hay = `${e.source} ${e.target}`.toLowerCase();
        if (!hay.includes(q)) return false;
      }
      return true;
    });
    res.sort((a, b) => {
      const av = a[sort.by];
      const bv = b[sort.by];
      if (typeof av === "string") {
        return sort.dir === "asc"
          ? av.localeCompare(bv)
          : bv.localeCompare(av);
      }
      return sort.dir === "asc" ? av - bv : bv - av;
    });
    return res;
  }, [events, filter, sort, metadata, plateMap]);

  const counts = useMemo(() => {
    const c = {
      total: events.length,
      tp: 0,
      fp: 0,
      uncertain: 0,
      pending: 0,
      samples: new Set(),
      avgRate: 0,
    };
    let rateSum = 0;
    events.forEach((e) => {
      c[
        e.verdict === "true_positive"
          ? "tp"
          : e.verdict === "false_positive"
            ? "fp"
            : e.verdict === "uncertain"
              ? "uncertain"
              : "pending"
      ]++;
      c.samples.add(e.source);
      c.samples.add(e.target);
      rateSum += e.rate;
    });
    c.avgRate = events.length ? rateSum / events.length : 0;
    c.samples = c.samples.size;
    return c;
  }, [events]);

  const selected =
    events.find((e) => e.id === selId) || events[0] || null;
  const setVerdict = (id, verdict) =>
    setRawEvents((prev) =>
      prev.map((e) => (e.id === id ? { ...e, verdict } : e)),
    );
  const setNote = (id, notes) =>
    setRawEvents((prev) =>
      prev.map((e) => (e.id === id ? { ...e, notes } : e)),
    );

  /** Add a user-curated event to the events list. Used by the
      "Explore new pairs" feature in the Scatterplots tab when the user
      identifies a missed contamination (false negative) and wants to
      include it in the curation report. The event is stamped with a
      string id starting with "manual-" so it's distinguishable from
      auto-loaded events. The caller chooses the verdict (TP / FP /
      Uncertain) and the note text. */
  const addManualEvent = (data) => {
    setRawEvents((prev) => {
      const nextManualNum = prev.filter((e) =>
        typeof e.id === "string" && e.id.startsWith("manual-"),
      ).length + 1;
      const newEvent = {
        id: `manual-${nextManualNum}`,
        source: data.source,
        target: data.target,
        rate: data.rate,
        score: data.score,
        introduced: data.introduced || [],
        verdict: data.verdict || "true_positive",
        notes: data.notes || "Manually added by user",
      };
      return [...prev, newEvent];
    });
  };

  /** Bulk-classify all same-subject events as false positives, with an
      auto-generated note explaining the rationale. Events that already
      have a manual verdict are skipped (to avoid overwriting user
      decisions). User notes are preserved by prepending the auto-note. */
  const [bulkConfirm, setBulkConfirm] = useState(null); // null | { kind, count, onConfirm }

  const bulkMarkSameSubjectAsFP = () => {
    if (!metadata) {
      setBulkConfirm({
        kind: "info",
        title: "Metadata required",
        body: "Load metadata.tsv first to bulk-classify same-subject events.",
      });
      return;
    }
    const matches = events.filter((e) => {
      const r = areRelated(metadata, e.source, e.target);
      return r?.related === true && r.kind === "subject" && e.verdict === "pending";
    });
    if (matches.length === 0) {
      setBulkConfirm({
        kind: "info",
        title: "Nothing to classify",
        body: "No pending same-subject events were found.",
      });
      return;
    }
    setBulkConfirm({
      kind: "confirm",
      title: `Mark ${matches.length} same-subject event${matches.length > 1 ? "s" : ""} as false positive?`,
      body:
        "These are longitudinal pairs (source and target share a subject_id) — biologically expected to share microbes, so CroCoDeEL flags are typically false positives.\n\n" +
        "An explanatory note will be added to each. Already-validated events are not affected.",
      confirmLabel: `Mark ${matches.length} as FP`,
      onConfirm: () => {
        const matchIds = new Set(matches.map((e) => e.id));
        setRawEvents((prev) =>
          prev.map((e) => {
            if (!matchIds.has(e.id)) return e;
            const r = areRelated(metadata, e.source, e.target);
            const subj = r?.value || "?";
            const autoNote = `Auto-classified as FP: longitudinal pair (same subject_id=${subj}).`;
            const newNote = e.notes ? `${autoNote}\n\n${e.notes}` : autoNote;
            return { ...e, verdict: "false_positive", notes: newNote };
          }),
        );
      },
    });
  };

  /** Bulk-classify all contaminations targeting a negative control as
      true positives. A clean NC should have no contamination — any flag
      flowing INTO an NC is therefore almost certainly real well-to-well
      leakage or carry-over, even if other criteria are weak. */
  const bulkMarkTowardNCAsTP = () => {
    if (!metadata) {
      setBulkConfirm({
        kind: "info",
        title: "Metadata required",
        body: "Load metadata.tsv first so the app can identify which samples are negative controls.",
      });
      return;
    }
    const matches = events.filter((e) => {
      const targetFlags = flagSample(e.target, metadata);
      return targetFlags.isControl && e.verdict === "pending";
    });
    if (matches.length === 0) {
      setBulkConfirm({
        kind: "info",
        title: "Nothing to classify",
        body: "No pending events targeting a negative control were found.",
      });
      return;
    }
    setBulkConfirm({
      kind: "confirm",
      title: `Mark ${matches.length} event${matches.length > 1 ? "s" : ""} toward NC as true positive?`,
      body:
        "These events flow into a sample tagged as a negative control. A clean NC should not carry biological signal, so any contamination reaching it is almost certainly real (well-to-well leakage, carry-over, or reagent contamination).\n\n" +
        "An explanatory note will be added to each. Already-validated events are not affected.",
      confirmLabel: `Mark ${matches.length} as TP`,
      onConfirm: () => {
        const matchIds = new Set(matches.map((e) => e.id));
        setRawEvents((prev) =>
          prev.map((e) => {
            if (!matchIds.has(e.id)) return e;
            const autoNote = `Auto-classified as TP: contamination flowing into negative control "${e.target}".`;
            const newNote = e.notes ? `${autoNote}\n\n${e.notes}` : autoNote;
            return { ...e, verdict: "true_positive", notes: newNote };
          }),
        );
      },
    });
  };

  /** Reset every event back to "pending" and clear notes. Used to start
      a curation session over from scratch. Asks for confirmation because
      this is destructive. */
  /** Apply a verdict (and an optional shared comment) to a precomputed
      list of event ids. Used by the "Bulk apply by criteria" dialog in
      Guided validation. If `comment` is empty, existing notes are
      preserved untouched; otherwise the comment is prepended to each
      event's notes so prior context is never destroyed. */
  const bulkApplyToEvents = (ids, verdict, comment) => {
    if (!ids || ids.length === 0) return;
    const idSet = new Set(ids);
    const stamp = new Date().toISOString().slice(0, 10);
    setBulkConfirm({
      kind: "confirm",
      title: `Apply "${verdict.replace("_", " ")}" to ${ids.length} event${ids.length > 1 ? "s" : ""}?`,
      body:
        `Existing verdicts on the matched events will be overwritten.` +
        (comment
          ? `\n\nThe comment will be prepended to each event's notes (existing notes are preserved).`
          : `\n\nNo comment provided — existing notes are kept untouched.`),
      confirmLabel: `Apply to ${ids.length}`,
      onConfirm: () => {
        setRawEvents((prev) =>
          prev.map((e) => {
            if (!idSet.has(e.id)) return e;
            const next = { ...e, verdict };
            if (comment) {
              const tag = `[bulk ${stamp}] ${comment}`;
              next.notes = e.notes ? `${tag}\n\n${e.notes}` : tag;
            }
            return next;
          }),
        );
      },
    });
  };

  const bulkResetAllVerdicts = () => {
    const decided = events.filter((e) => e.verdict !== "pending").length;
    const noted = events.filter((e) => e.notes && e.notes.length > 0).length;
    if (decided === 0 && noted === 0) {
      setBulkConfirm({
        kind: "info",
        title: "Nothing to reset",
        body: "No verdicts or notes have been set yet.",
      });
      return;
    }
    setBulkConfirm({
      kind: "confirm",
      title: "Reset all curation work?",
      body:
        `This will clear ${decided} verdict${decided !== 1 ? "s" : ""} and ` +
        `${noted} note${noted !== 1 ? "s" : ""}, returning every event to the "pending" state.\n\n` +
        "The files you opened (events, abundance, metadata, plate map) are NOT affected.",
      confirmLabel: "Reset everything",
      destructive: true,
      onConfirm: () => {
        setRawEvents((prev) =>
          prev.map((e) => ({ ...e, verdict: "pending", notes: "" })),
        );
      },
    });
  };

  /* ---- file loaders ---- */
  const loadEvents = async (file) => {
    try {
      const text = await file.text();
      const parsed = parseEvents(text);
      setRawEvents(parsed.events);
      setRunMetadata(parsed.runMetadata);
      setErr(null);
      setTab("overview");
    } catch (e) {
      setErr(`Events file: ${e.message}`);
    }
  };

  const loadAbundance = async (file) => {
    try {
      const text = await file.text();
      const parsed = parseAbundance(text);
      if (!parsed) throw new Error("Could not parse abundance table");
      setAb(parsed);
      setErr(null);
    } catch (e) {
      setErr(`Abundance file: ${e.message}`);
    }
  };

  const [demoLoading, setDemoLoading] = useState(false);
  const loadDemo = async () => {
    setDemoLoading(true);
    setErr(null);
    try {
      // Derive the base URL from the current location instead of
      // import.meta.env.BASE_URL — that keeps this file parseable in
      // non-module contexts (e.g. Claude's artifact preview) while still
      // working correctly when Vite serves it under a nested base path.
      const path = window.location.pathname;
      const base = path.endsWith("/")
        ? path
        : path.replace(/\/[^/]*$/, "/") || "/";
      const join = (p) => `${base.replace(/\/$/, "")}/demo/${p}`;

      // Required files
      const [evRes, abRes] = await Promise.all([
        fetch(join("contamination_events.tsv")),
        fetch(join("species_abundance.tsv")),
      ]);
      if (!evRes.ok) throw new Error(`events (${evRes.status})`);
      if (!abRes.ok) throw new Error(`abundance (${abRes.status})`);
      const [evText, abText] = await Promise.all([evRes.text(), abRes.text()]);
      const parsedAb = parseAbundance(abText);
      if (!parsedAb) throw new Error("Could not parse demo abundance table");
      const parsedEvents = parseEvents(evText);
      setRawEvents(parsedEvents.events);
      setRunMetadata(parsedEvents.runMetadata);
      setAb(parsedAb);

      // Optional files — load if present, ignore 404s silently
      try {
        const pmRes = await fetch(join("plate_map.tsv"));
        if (pmRes.ok) {
          const pmText = await pmRes.text();
          setPlateMap(parsePlateMap(pmText));
        }
      } catch {
        // ignore
      }
      try {
        const mdRes = await fetch(join("metadata.tsv"));
        if (mdRes.ok) {
          const mdText = await mdRes.text();
          setMetadata(parseMetadata(mdText));
        }
      } catch {
        // ignore
      }

      setTab("overview");
    } catch (e) {
      setErr(
        `Demo data: ${e.message}. Make sure public/demo/contamination_events.tsv and public/demo/species_abundance.tsv exist in the deployed site.`,
      );
    } finally {
      setDemoLoading(false);
    }
  };

  /** Load a paper dataset from the manifest. The dataset object comes
      from datasets/manifest.json and includes paths to events,
      abundance, optional metadata and plate_map files. If the user
      already has data loaded, ask for confirmation first via the
      centralised modal — replacing without warning would silently
      destroy curation work. */
  const loadDataset = async (dataset) => {
    const performLoad = async () => {
      setErr(null);
      try {
        const path = window.location.pathname;
        const base = path.endsWith("/")
          ? path
          : path.replace(/\/[^/]*$/, "/") || "/";
        const join = (p) => `${base.replace(/\/$/, "")}/datasets/${p}`;

        // Required files
        const evPath = dataset.files.events;
        const abPath = dataset.files.abundance;
        if (!evPath || !abPath) {
          throw new Error("Dataset manifest is missing events or abundance file");
        }
        const [evRes, abRes] = await Promise.all([
          fetch(join(evPath)),
          fetch(join(abPath)),
        ]);
        if (!evRes.ok) throw new Error(`events (${evRes.status})`);
        if (!abRes.ok) throw new Error(`abundance (${abRes.status})`);
        const [evText, abText] = await Promise.all([evRes.text(), abRes.text()]);
        const parsedAb = parseAbundance(abText);
        if (!parsedAb) throw new Error("Could not parse abundance table");
        const parsedEvents = parseEvents(evText);

        // Reset session state to avoid mixing files from different datasets
        setRawEvents(parsedEvents.events);
        setRunMetadata(parsedEvents.runMetadata);
        setAb(parsedAb);
        setMetadata(null);
        setPlateMap(null);
        setSelId(null);

        // Optional files — load if present, skip silently otherwise
        if (dataset.files.metadata) {
          try {
            const mdRes = await fetch(join(dataset.files.metadata));
            if (mdRes.ok) {
              const mdText = await mdRes.text();
              setMetadata(parseMetadata(mdText));
            }
          } catch {
            // ignore
          }
        }
        if (dataset.files.plate_map) {
          try {
            const pmRes = await fetch(join(dataset.files.plate_map));
            if (pmRes.ok) {
              const pmText = await pmRes.text();
              setPlateMap(parsePlateMap(pmText));
            }
          } catch {
            // ignore
          }
        }

        setTab("overview");
      } catch (e) {
        setErr(
          `Dataset "${dataset.title}": ${e.message}. Make sure the files referenced in datasets/manifest.json exist in the deployed site.`,
        );
      }
    };

    const hasData = rawEvents.length > 0 || ab || metadata || plateMap;
    if (!hasData) {
      await performLoad();
      return;
    }
    setBulkConfirm({
      kind: "confirm",
      title: `Replace your session with "${dataset.short_title || dataset.title}"?`,
      body:
        "Loading this dataset will replace your currently-loaded events, abundance, metadata, plate map and verdicts.\n\n" +
        "The original files on disk are not affected — you can re-open them after exploring this dataset.",
      confirmLabel: "Replace and load",
      destructive: true,
      onConfirm: () => {
        performLoad();
      },
    });
  };

  /** Open the guided tour. The tour assumes the bundled demo dataset is
      loaded (it walks through tabs whose content references known demo
      events, plate layout, etc.). If the user already has their own
      data loaded, ask via the centralised confirm modal before we wipe
      it and fetch the demo. Cancelling leaves the session untouched. */
  const startTutorial = () => {
    const hasData = rawEvents.length > 0 || ab || metadata || plateMap;
    if (!hasData) {
      setTutorialOpen(true);
      return;
    }
    setBulkConfirm({
      kind: "confirm",
      title: "Replace your session with the demo dataset?",
      body:
        "The guided tour walks through the bundled Lou et al. 2023 P3 demo dataset. To run it, your currently-loaded events, abundance, metadata, plate map and verdicts will be replaced.\n\n" +
        "The original files on disk are not affected — you can re-open them after the tour.",
      confirmLabel: "Replace and start tour",
      destructive: true,
      onConfirm: () => {
        // Clear current session so the welcome step can load demo cleanly
        setRawEvents([]);
        setRunMetadata(null);
        setAb(null);
        setMetadata(null);
        setPlateMap(null);
        setSelId(null);
        setErr(null);
        setTutorialOpen(true);
      },
    });
  };

  /* ---- export ---- */
  const downloadFile = (content, name, mime) => {
    const blob = new Blob([content], { type: mime });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = name;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportReport = (onlyTP = true) => {
    const kept = events.filter((e) =>
      onlyTP
        ? e.verdict === "true_positive"
        : e.verdict !== "false_positive",
    );
    const header = [
      "source",
      "target",
      "contamination_rate",
      "probability",
      "introduced_species",
      "verdict",
      "notes",
    ];
    const lines = [header.join("\t")];
    kept.forEach((e) => {
      lines.push(
        [
          e.source,
          e.target,
          e.rate,
          e.score,
          e.introduced.join(","),
          e.verdict,
          e.notes.replace(/\t/g, " "),
        ].join("\t"),
      );
    });
    downloadFile(
      lines.join("\n"),
      `contamination_events_curated${onlyTP ? "_TP_only" : ""}.tsv`,
      "text/tab-separated-values",
    );
  };

  const exportJSON = () => {
    const payload = {
      generated: new Date().toISOString(),
      counts: {
        total: counts.total,
        true_positive: counts.tp,
        false_positive: counts.fp,
        uncertain: counts.uncertain,
        pending: counts.pending,
      },
      has_metadata: !!metadata,
      has_plate_map: !!plateMap,
      events: events.map((e) => ({
        source: e.source,
        target: e.target,
        contamination_rate: e.rate,
        probability: e.score,
        introduced_species: e.introduced,
        verdict: e.verdict,
        notes: e.notes,
        relatedness: areRelated(metadata, e.source, e.target),
        plate_distance: plateDistance(plateMap, e.source, e.target),
        cascade: e.cascade,
      })),
    };
    downloadFile(
      JSON.stringify(payload, null, 2),
      "crocodeel_curation_report.json",
      "application/json",
    );
  };

  /** Generate a self-contained, comprehensive HTML report styled for
      printing. Includes summary stats, run parameters, an overview
      curation table, AND a detailed page per event with the scatterplot
      (inline SVG), the 5 diagnostic checks, the introduced species
      list, and the cascade chain when relevant. The user opens the
      file and uses their browser's "Save as PDF" (Ctrl+P or Cmd+P) to
      get a PDF without any external dependency. */
  const exportHTMLReport = () => {
    const escapeHTML = (s) =>
      String(s == null ? "" : s)
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/"/g, "&quot;");

    const verdictPill = (v) => {
      const tone =
        v === "TP"
          ? { bg: "#00a3a6", label: "True positive" }
          : v === "FP"
            ? { bg: "#ed6e6c", label: "False positive" }
            : v === "UNCERTAIN"
              ? { bg: "#c4c0b3", label: "Uncertain" }
              : { bg: "#e6e8e8", label: "Pending", textColor: "#5a5550" };
      return `<span style="background:${tone.bg};color:${tone.textColor || "#fff"};padding:2px 8px;border-radius:2px;font-size:10px;font-weight:700;letter-spacing:0.05em;text-transform:uppercase;">${tone.label}</span>`;
    };

    /** Build a small SVG scatterplot for an event. Mirrors the visual
        language of the main Scatterplot component (deep teal points
        for off-line, salmon for on-line, black dashed y=x, salmon
        dashed contamination line). Uses log axes from 1e-5 to 1e0. */
    const renderScatterSVG = (event) => {
      if (!ab) return "<em style='color:#797870'>abundance table required</em>";
      const sc = buildScatter(ab, event);
      if (!sc || sc.error || sc.points.length === 0) {
        return `<em style='color:#797870'>${escapeHTML(sc?.error || "no plot available")}</em>`;
      }
      const W = 360,
        H = 300;
      const pad = { l: 50, r: 12, t: 12, b: 36 };
      const plotW = W - pad.l - pad.r;
      const plotH = H - pad.t - pad.b;
      // Log10 mapping with a fixed range -5 .. 0
      const LMIN = -5;
      const LMAX = 0;
      const sx = (logV) =>
        pad.l + ((logV - LMIN) / (LMAX - LMIN)) * plotW;
      const sy = (logV) =>
        pad.t + plotH - ((logV - LMIN) / (LMAX - LMIN)) * plotH;
      const safeLog = (v) => (v > 0 ? Math.max(LMIN, Math.log10(v)) : LMIN);

      // Gridlines + tick labels at log -5, -3, -1
      const ticks = [-5, -3, -1];
      const tickLabels = { "-5": "1e-5", "-3": "1e-3", "-1": "1e-1" };
      let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${W} ${H}" width="${W}" height="${H}" style="background:#fff;border:1px solid #e6e8e8;border-radius:3px;">`;
      ticks.forEach((t) => {
        svg += `<line x1="${sx(t)}" y1="${pad.t}" x2="${sx(t)}" y2="${pad.t + plotH}" stroke="#eee" stroke-width="0.5"/>`;
        svg += `<line x1="${pad.l}" y1="${sy(t)}" x2="${pad.l + plotW}" y2="${sy(t)}" stroke="#eee" stroke-width="0.5"/>`;
        svg += `<text x="${sx(t)}" y="${pad.t + plotH + 14}" text-anchor="middle" font-size="9" fill="#797870">${tickLabels[t]}</text>`;
        svg += `<text x="${pad.l - 6}" y="${sy(t) + 3}" text-anchor="end" font-size="9" fill="#797870">${tickLabels[t]}</text>`;
      });
      // Axes
      svg += `<line x1="${pad.l}" y1="${pad.t + plotH}" x2="${pad.l + plotW}" y2="${pad.t + plotH}" stroke="#275662" stroke-width="1"/>`;
      svg += `<line x1="${pad.l}" y1="${pad.t}" x2="${pad.l}" y2="${pad.t + plotH}" stroke="#275662" stroke-width="1"/>`;
      // y = x diagonal
      svg += `<line x1="${sx(LMIN)}" y1="${sy(LMIN)}" x2="${sx(LMAX)}" y2="${sy(LMAX)}" stroke="#000" stroke-width="0.7" stroke-dasharray="2 4" opacity="0.6"/>`;
      // Contamination line: source = target / rate, i.e. log_y = log_x - logC
      if (sc.logC != null) {
        const x1 = LMIN;
        const y1 = LMIN - sc.logC;
        const x2 = LMAX;
        const y2 = LMAX - sc.logC;
        // Clip if outside plot range
        const clip = (a, b) => Math.max(LMIN, Math.min(LMAX, b - sc.logC));
        svg += `<line x1="${sx(x1)}" y1="${sy(Math.max(LMIN, Math.min(LMAX, y1)))}" x2="${sx(x2)}" y2="${sy(Math.max(LMIN, Math.min(LMAX, y2)))}" stroke="#ed6e6c" stroke-width="1.2" stroke-dasharray="5 3"/>`;
      }
      // Off-line points (deep teal, small)
      sc.points
        .filter((p) => !p.onLine)
        .forEach((p) => {
          const x = sx(safeLog(p.x));
          const y = sy(safeLog(p.y));
          svg += `<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="2" fill="#275662" fill-opacity="0.4"/>`;
        });
      // On-line points (salmon, larger, with stroke)
      sc.points
        .filter((p) => p.onLine)
        .forEach((p) => {
          const x = sx(safeLog(p.x));
          const y = sy(safeLog(p.y));
          svg += `<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="3" fill="#ed6e6c" stroke="#b84442" stroke-width="0.5"/>`;
        });
      // Axis labels
      svg += `<text x="${pad.l + plotW / 2}" y="${H - 4}" text-anchor="middle" font-size="9" fill="#275662">Target — ${escapeHTML(event.target)}</text>`;
      svg += `<text x="14" y="${pad.t + plotH / 2}" text-anchor="middle" font-size="9" fill="#275662" transform="rotate(-90 14 ${pad.t + plotH / 2})">Source — ${escapeHTML(event.source)}</text>`;
      svg += `</svg>`;
      return svg;
    };

    /** Render the 5 diagnostic checks for an event as a small list. */
    const renderDiagChecks = (event) => {
      const sc = buildScatter(ab, event);
      if (!sc || sc.error) return "<em style='color:#797870'>abundance table required</em>";
      const di = lineDiagnostics(sc);
      const ab2 = pointsAboveLine(sc);
      const mi = missingAbundantFromSource(ab, event.source, event.target, event.rate);
      const score = automaticScore(di, ab2, mi, event.cascade);
      return `
        <ul class="checklist">
          ${score.reasons
            .map(
              (r) =>
                `<li><span class="${r.ok ? "ok" : "bad"}">${r.ok ? "✓" : "✗"}</span> ${escapeHTML(r.label)}</li>`,
            )
            .join("")}
        </ul>
        <div class="aggregate ${score.good === score.total ? "all-pass" : score.good >= Math.ceil(score.total * 0.6) ? "warn" : "fail"}">
          ${score.good} / ${score.total} —
          ${score.good === score.total
            ? "CONTAMINATED — CroCoDeEL is probably right"
            : score.good >= Math.ceil(score.total * 0.6)
              ? "POSSIBLY NOT CONTAMINATED — use CroCoDeEL's call with prudence"
              : "PROBABLY NOT CONTAMINATED — review carefully"}
        </div>
      `;
    };

    const overviewRows = events
      .map((e, i) => {
        const rel = areRelated(metadata, e.source, e.target);
        const pd = plateDistance(plateMap, e.source, e.target);
        return `
        <tr>
          <td class="num">${i + 1}</td>
          <td>${escapeHTML(e.source)}</td>
          <td>${escapeHTML(e.target)}</td>
          <td class="num">${(e.rate * 100).toFixed(2)}%</td>
          <td class="num">${e.score.toFixed(3)}</td>
          <td class="num">${e.introducedPct == null ? "—" : `${e.introducedPct.toFixed(1)}%`}</td>
          <td>${verdictPill(e.verdict)}</td>
          <td>${rel?.related ? `<em>${escapeHTML(rel.reason)}</em>` : ""}</td>
          <td>${pd != null ? `Δ ${pd}` : ""}</td>
          <td>${e.cascade ? "yes" : ""}</td>
        </tr>`;
      })
      .join("");

    const detailPages = events
      .map((e, i) => {
        const rel = areRelated(metadata, e.source, e.target);
        const pd = plateDistance(plateMap, e.source, e.target);
        const introducedList = (e.introduced || [])
          .slice(0, 30)
          .map((sp) => `<code>${escapeHTML(sp)}</code>`)
          .join(", ");
        const introducedExtra =
          e.introduced && e.introduced.length > 30
            ? ` <em>(+${e.introduced.length - 30} more)</em>`
            : "";

        const cascadeBlock = e.cascade
          ? `
          <h4>Cascade detected</h4>
          <p>This event has ${e.cascade.points_above} points above its line, partially explained by upstream contamination of the source:</p>
          <ul>
            ${e.cascade.explained
              .map(
                (c) =>
                  `<li><strong>${escapeHTML(c.upstream_source)} → ${escapeHTML(e.source)}</strong> (${(c.rate * 100).toFixed(2)}%) explains ${c.species_explained} species</li>`,
              )
              .join("")}
          </ul>`
          : "";

        const contextBlock = `
          <table class="kv">
            <tbody>
              <tr><th>Source</th><td><code>${escapeHTML(e.source)}</code></td></tr>
              <tr><th>Target</th><td><code>${escapeHTML(e.target)}</code></td></tr>
              <tr><th>Contamination rate</th><td>${(e.rate * 100).toFixed(2)}%</td></tr>
              <tr><th>RF probability</th><td>${e.score.toFixed(3)}</td></tr>
              ${e.introducedPct == null ? "" : `<tr><th>Introduced (% of target species)</th><td>${e.introducedPct.toFixed(1)}%</td></tr>`}
              <tr><th>Verdict</th><td>${verdictPill(e.verdict)}</td></tr>
              ${rel?.related ? `<tr><th>Sample relatedness</th><td><em>${escapeHTML(rel.reason)}</em></td></tr>` : ""}
              ${pd != null ? `<tr><th>Plate distance</th><td>Δ ${pd} well${pd > 1 ? "s" : ""}</td></tr>` : ""}
              <tr><th>Introduced species</th><td>${e.introduced?.length || 0} total. ${introducedList}${introducedExtra}</td></tr>
              ${e.notes ? `<tr><th>Curator notes</th><td>${escapeHTML(e.notes)}</td></tr>` : ""}
            </tbody>
          </table>`;

        return `
        <div class="event-page">
          <h3>Event ${i + 1} of ${events.length} · ${escapeHTML(e.source)} → ${escapeHTML(e.target)}</h3>
          <div class="event-grid">
            <div class="event-plot">
              ${renderScatterSVG(e)}
            </div>
            <div class="event-info">
              ${contextBlock}
            </div>
          </div>
          <h4>Diagnostic checks</h4>
          ${renderDiagChecks(e)}
          ${cascadeBlock}
        </div>`;
      })
      .join("");

    const runMetaSection = runMetadata
      ? `
      <h2>CroCoDeEL run parameters</h2>
      <table class="kv">
        <tbody>
          ${Object.entries(runMetadata)
            .map(
              ([k, v]) =>
                `<tr><th>${escapeHTML(k)}</th><td>${escapeHTML(typeof v === "object" ? JSON.stringify(v) : v)}</td></tr>`,
            )
            .join("")}
        </tbody>
      </table>`
      : "";

    const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8" />
<title>CroCoDeEL curation report</title>
<style>
  @page { size: A4; margin: 1.5cm; }
  body {
    font-family: "Avenir Next", "Nunito Sans", system-ui, -apple-system, sans-serif;
    color: #275662;
    font-size: 12px;
    line-height: 1.5;
    max-width: 1100px;
    margin: 0 auto;
    padding: 24px;
  }
  h1 {
    font-family: "Raleway", sans-serif;
    font-size: 24px;
    font-weight: 800;
    color: #275662;
    margin: 0 0 4px;
  }
  h2 {
    font-family: "Raleway", sans-serif;
    font-size: 14px;
    font-weight: 700;
    color: #275662;
    margin-top: 32px;
    margin-bottom: 12px;
    border-bottom: 1px solid #e6e8e8;
    padding-bottom: 4px;
  }
  h3 {
    font-family: "Raleway", sans-serif;
    font-size: 13px;
    font-weight: 700;
    color: #275662;
    margin: 0 0 12px;
  }
  h4 {
    font-family: "Raleway", sans-serif;
    font-size: 11px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    color: #ed6e6c;
    margin: 16px 0 8px;
  }
  .meta {
    color: #797870;
    font-size: 11px;
    margin-bottom: 24px;
  }
  .summary {
    display: grid;
    grid-template-columns: repeat(5, 1fr);
    gap: 12px;
    margin: 16px 0;
  }
  .stat {
    border: 1px solid #e6e8e8;
    border-radius: 3px;
    padding: 12px;
  }
  .stat .label {
    font-size: 10px;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    color: #797870;
    font-weight: 700;
    margin-bottom: 4px;
  }
  .stat .value {
    font-size: 20px;
    font-weight: 800;
  }
  .stat.tp .value { color: #00a3a6; }
  .stat.fp .value { color: #ed6e6c; }
  .stat.unc .value { color: #797870; }
  table {
    width: 100%;
    border-collapse: collapse;
    font-size: 10px;
  }
  table th, table td {
    border: 1px solid #e6e8e8;
    padding: 6px 8px;
    text-align: left;
    vertical-align: top;
  }
  table th {
    background: #f6f7f7;
    font-weight: 700;
    font-size: 10px;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #797870;
  }
  td.num { text-align: right; font-variant-numeric: tabular-nums; }
  table.kv th { width: 25%; }
  code {
    font-family: ui-monospace, "SF Mono", Menlo, monospace;
    font-size: 10px;
    background: #f6f7f7;
    padding: 1px 4px;
    border-radius: 2px;
  }
  .legend {
    background: #f6f7f7;
    border: 1px solid #e6e8e8;
    border-radius: 3px;
    padding: 12px 16px;
    font-size: 11px;
    line-height: 1.6;
    margin: 16px 0;
  }
  .legend strong { color: #275662; }
  .legend-swatch {
    display: inline-block;
    width: 14px;
    height: 14px;
    vertical-align: middle;
    border-radius: 2px;
    margin-right: 4px;
  }
  .event-page {
    page-break-before: always;
    padding-top: 12px;
  }
  .event-page:first-of-type { page-break-before: auto; }
  .event-grid {
    display: grid;
    grid-template-columns: 360px 1fr;
    gap: 16px;
    align-items: start;
    margin-bottom: 12px;
  }
  .event-info table { font-size: 10px; }
  .checklist {
    list-style: none;
    padding: 0;
    margin: 8px 0;
  }
  .checklist li {
    padding: 3px 0;
    font-size: 11px;
  }
  .checklist .ok { color: #00a3a6; font-weight: 700; }
  .checklist .bad { color: #ed6e6c; font-weight: 700; }
  .aggregate {
    margin-top: 8px;
    padding: 6px 10px;
    border-radius: 2px;
    font-size: 11px;
    font-weight: 700;
    letter-spacing: 0.02em;
  }
  .aggregate.all-pass { background: #d8f0f1; color: #00a3a6; }
  .aggregate.warn { background: #fde6d8; color: #b46028; }
  .aggregate.fail { background: #fce0df; color: #b84442; }
  .footnote {
    margin-top: 32px;
    padding-top: 12px;
    border-top: 1px solid #e6e8e8;
    color: #797870;
    font-size: 10px;
  }
  @media print {
    body { padding: 0; }
    h2 { page-break-after: avoid; }
    h3 { page-break-after: avoid; }
    table { page-break-inside: auto; }
    tr { page-break-inside: avoid; }
    .event-page { page-break-before: always; }
  }
</style>
</head>
<body>
  <h1>CroCoDeEL curation report</h1>
  <div class="meta">
    Generated ${new Date().toLocaleString()} ·
    ${counts.total} event${counts.total > 1 ? "s" : ""} curated
  </div>

  <h2>Summary</h2>
  <div class="summary">
    <div class="stat"><div class="label">Total</div><div class="value">${counts.total}</div></div>
    <div class="stat tp"><div class="label">True positive</div><div class="value">${counts.tp}</div></div>
    <div class="stat fp"><div class="label">False positive</div><div class="value">${counts.fp}</div></div>
    <div class="stat unc"><div class="label">Uncertain</div><div class="value">${counts.uncertain}</div></div>
    <div class="stat"><div class="label">Pending</div><div class="value">${counts.pending}</div></div>
  </div>

  ${runMetaSection}

  <h2>Reading guide</h2>
  <div class="legend">
    Each event below has its own scatterplot of <strong>source</strong> abundance (Y axis) versus
    <strong>target</strong> abundance (X axis), in log scale.
    <ul style="margin:8px 0;padding-left:20px;">
      <li><span class="legend-swatch" style="background:#275662;opacity:0.4;"></span> Off-line species (target's biology, not transferred from source)</li>
      <li><span class="legend-swatch" style="background:#ed6e6c;border:0.5px solid #b84442;"></span> On-line species (introduced into target by contamination)</li>
      <li><span class="legend-swatch" style="background:transparent;border-top:1px dashed #000;height:2px;width:16px;border-radius:0;"></span> y = x diagonal (equal abundance reference)</li>
      <li><span class="legend-swatch" style="background:transparent;border-top:1.5px dashed #ed6e6c;height:2px;width:16px;border-radius:0;"></span> Contamination line (where transferred species sit, at offset log10(rate))</li>
    </ul>
    The 5 <strong>diagnostic checks</strong> below each plot test the line's shape, density,
    spread, abundant-species coverage, and absence of points above the line. Failing
    criterion 04 (missing core source species in target) is the strongest red flag.
  </div>

  <h2>Curation overview</h2>
  <table>
    <thead>
      <tr>
        <th>#</th>
        <th>Source</th>
        <th>Target</th>
        <th>Rate</th>
        <th>Probability</th>
        <th>Introduced %</th>
        <th>Verdict</th>
        <th>Related</th>
        <th>Plate</th>
        <th>Cascade</th>
      </tr>
    </thead>
    <tbody>
      ${overviewRows}
    </tbody>
  </table>

  <h2>Per-event detail</h2>
  ${detailPages}

  <div class="footnote">
    Generated by the CroCoDeEL Interpretation Console (Anthropic Claude · INRAE Metagenopolis).
    Reference: Goulet et al. 2025, bioRxiv 10.1101/2025.01.15.633153.
    To save as PDF: use your browser's print dialog (Ctrl+P / Cmd+P) and choose "Save as PDF".
  </div>
</body>
</html>`;
    downloadFile(html, "crocodeel_curation_report.html", "text/html");
  };

  /* ---- diagnostics for selected event ---- */
  const scatter = useMemo(
    () => (selected ? buildScatter(ab, selected) : null),
    [ab, selected],
  );
  const diag = useMemo(() => lineDiagnostics(scatter), [scatter]);
  const above = useMemo(() => pointsAboveLine(scatter), [scatter]);
  const missing = useMemo(
    () =>
      selected && ab
        ? missingAbundantFromSource(ab, selected.source, selected.target, selected.rate)
        : null,
    [ab, selected],
  );
  const autoScore = useMemo(
    () => automaticScore(diag, above, missing, selected?.cascade),
    [diag, above, missing, selected],
  );

  /* ============================================================
     RENDER
     ============================================================ */
  return (
    <div
      className="min-h-screen"
      style={{
        background: "#fff",
        color: "#275662",
        fontFamily:
          '"Avenir Next", "Nunito Sans", system-ui, -apple-system, sans-serif',
        // Reserve room on the right when the tutorial panel is open so
        // content doesn't slide under it.
        paddingRight: tutorialOpen ? 360 : 0,
        transition: "padding-right 0.2s ease-out",
      }}
    >
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Raleway:wght@400;500;600;700;800&family=Nunito+Sans:opsz,wght@6..12,400;6..12,500;6..12,600;6..12,700&display=swap');
        .tabular { font-variant-numeric: tabular-nums; }
        ::-webkit-scrollbar { width: 8px; height: 8px; }
        ::-webkit-scrollbar-thumb { background: #c4c0b3; border-radius: 4px; }
        ::-webkit-scrollbar-thumb:hover { background: #00a3a6; }
      `}</style>

      {/* ==================== BETA BANNER ==================== */}
      <div
        style={{
          background: "#ed6e6c",
          color: "#fff",
          textAlign: "center",
          padding: "6px 16px",
          fontSize: 12,
          fontWeight: 700,
          letterSpacing: "0.04em",
          fontFamily: '"Raleway", sans-serif',
        }}
      >
        <span
          style={{
            display: "inline-block",
            background: "#fff",
            color: "#ed6e6c",
            padding: "1px 8px",
            borderRadius: 2,
            marginRight: 10,
            fontSize: 10,
            fontWeight: 800,
            letterSpacing: "0.08em",
            verticalAlign: "1px",
          }}
        >
          BETA
        </span>
        Active development — feedback welcome and bugs expected. Verify findings before publication.
      </div>

      {/* ==================== HEADER ==================== */}
      <header style={{ borderBottom: "3px solid #00a3a6", background: "#fff" }}>
        <div className="max-w-7xl mx-auto px-6 py-5">
          <div className="flex items-center gap-3 flex-wrap">
            <img
              src={CROCODEEL_LOGO}
              alt="CroCoDeEL"
              style={{
                height: 46,
                width: 46,
                borderRadius: "50%",
                display: "block",
              }}
            />
            <div className="leading-tight">
              <div
                className="text-[20px]"
                style={{
                  color: "#275662",
                  fontWeight: 800,
                  letterSpacing: "-0.01em",
                  fontFamily: '"Raleway", sans-serif',
                }}
              >
                CroCoDeEL
              </div>
              <div
                className="text-[10px] uppercase tracking-[0.15em]"
                style={{
                  color: "#797870",
                  fontFamily: '"Raleway", sans-serif',
                }}
              >
                Interpretation console
              </div>
            </div>
            <a
              href="https://github.com/metagenopolis/CroCoDeEL"
              target="_blank"
              rel="noopener noreferrer"
              title="View CroCoDeEL on GitHub (metagenopolis/CroCoDeEL)"
              className="ml-auto flex items-center gap-2 px-4 py-2 rounded-sm"
              style={{
                background: "#275662",
                color: "#fff",
                border: "1px solid #275662",
                fontSize: 13,
                fontWeight: 700,
                fontFamily: '"Raleway", sans-serif',
                textDecoration: "none",
                letterSpacing: "0.02em",
                transition: "all 0.15s",
                boxShadow: "0 1px 3px rgba(39,86,98,0.2)",
              }}
              onMouseOver={(e) => {
                e.currentTarget.style.background = "#00a3a6";
                e.currentTarget.style.borderColor = "#00a3a6";
                e.currentTarget.style.boxShadow =
                  "0 2px 6px rgba(0,163,166,0.35)";
              }}
              onMouseOut={(e) => {
                e.currentTarget.style.background = "#275662";
                e.currentTarget.style.borderColor = "#275662";
                e.currentTarget.style.boxShadow =
                  "0 1px 3px rgba(39,86,98,0.2)";
              }}
            >
              <svg
                aria-hidden="true"
                viewBox="0 0 24 24"
                width="16"
                height="16"
                fill="currentColor"
                style={{ display: "block" }}
              >
                <path d="M12 .5C5.65.5.5 5.65.5 12c0 5.08 3.29 9.39 7.86 10.92.58.11.79-.25.79-.56 0-.28-.01-1.02-.02-2-3.2.7-3.87-1.54-3.87-1.54-.52-1.32-1.27-1.67-1.27-1.67-1.04-.71.08-.7.08-.7 1.15.08 1.76 1.18 1.76 1.18 1.02 1.75 2.69 1.25 3.34.95.1-.74.4-1.25.72-1.54-2.55-.29-5.24-1.28-5.24-5.69 0-1.26.45-2.29 1.18-3.1-.12-.29-.51-1.46.11-3.05 0 0 .97-.31 3.18 1.18.92-.26 1.91-.39 2.89-.39.98 0 1.97.13 2.89.39 2.21-1.49 3.18-1.18 3.18-1.18.62 1.59.23 2.76.11 3.05.74.81 1.18 1.84 1.18 3.1 0 4.42-2.69 5.39-5.25 5.68.41.36.78 1.06.78 2.13 0 1.54-.01 2.78-.01 3.16 0 .31.21.68.8.56C20.21 21.39 23.5 17.08 23.5 12 23.5 5.65 18.35.5 12 .5z" />
              </svg>
              <span>GitHub · metagenopolis/CroCoDeEL</span>
            </a>
          </div>
        </div>
      </header>

      {/* ==================== SUB-BANNER ==================== */}
      <section className="bg-white">
        <div className="max-w-7xl mx-auto px-6 py-6">
          <div
            className="flex flex-wrap gap-6 items-end justify-between"
          >
            <div style={{ flex: "1 1 520px", minWidth: 0 }}>
              <div className="flex items-center gap-2 mb-2">
                <Chevron size={14} color="#ed6e6c" />
                <span
                  className="text-[11px] tracking-[0.15em] uppercase"
                  style={{
                    color: "#ed6e6c",
                    fontWeight: 700,
                    fontFamily: '"Raleway", sans-serif',
                  }}
                >
                  Metagenomics · Cross-sample contamination detection
                </span>
              </div>
              <h1
                className="text-[42px] leading-[1.05] tracking-tight"
                style={{
                  color: "#275662",
                  fontWeight: 800,
                  fontFamily: '"Raleway", sans-serif',
                }}
              >
                Interpreting CroCoDeEL results
              </h1>
              <p className="mt-3 text-[15px] leading-relaxed text-stone-700 max-w-xl">
                Open your events file and abundance table, then walk through each
                flagged pair with interactive scatterplots, diagnostic checks
                and a guided validation workflow. Export a curated TSV and
                HTML report when you are done.
              </p>
            </div>
            {/* Privacy badge — prominent, reassuring */}
            <div
              className="flex items-start gap-2 px-3 py-2 rounded-sm"
              style={{
                background: "rgba(0, 163, 166, 0.08)",
                border: "1px solid #00a3a6",
                flex: "1 1 320px",
                maxWidth: 420,
              }}
            >
              <ShieldCheck
                className="w-4 h-4 shrink-0"
                style={{ color: "#00a3a6", marginTop: 2 }}
              />
              <div>
                <div
                  className="text-[12px]"
                  style={{
                    color: "#275662",
                    fontWeight: 600,
                    fontFamily: '"Raleway", sans-serif',
                  }}
                >
                  100% browser-based — your files never leave your computer
                </div>
                <div
                  className="text-[11px] mt-1"
                  style={{ color: "#5a5550", lineHeight: 1.5 }}
                >
                  Your work is auto-saved locally so you can close the tab and
                  come back anytime (unless your browser cache is cleared). Use{" "}
                  <strong style={{ color: "#275662" }}>Clear session</strong>{" "}
                  on the files bar to wipe everything and start fresh.
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* ==================== UPLOAD BAR ==================== */}
      <section
        data-tutorial="upload-bar"
        style={{
          background: "#f6f7f7",
          borderTop: "1px solid #e6e8e8",
          borderBottom: "1px solid #e6e8e8",
        }}
      >
        <div className="max-w-7xl mx-auto px-6 py-4">
          <div className="flex items-center justify-between gap-4 mb-3 flex-wrap">
            <div
              className="flex items-center gap-2 text-[11px]"
              style={{ color: "#797870", fontFamily: '"Raleway", sans-serif' }}
            >
              <ShieldCheck className="w-3.5 h-3.5" style={{ color: "#00a3a6" }} />
              <span>
                Files stay local: parsing happens entirely in your browser. No
                data is sent to any server.
              </span>
            </div>
            {(rawEvents.length > 0 || ab || metadata || plateMap) && (
              <button
                onClick={() => {
                  setBulkConfirm({
                    kind: "confirm",
                    title: "Clear the entire session?",
                    body:
                      "This removes the loaded events, abundance, metadata and plate map, plus all your verdicts and notes.\n\n" +
                      "The original files on disk are not affected.",
                    confirmLabel: "Clear session",
                    destructive: true,
                    onConfirm: () => {
                      setRawEvents([]);
                      setRunMetadata(null);
                      setAb(null);
                      setMetadata(null);
                      setPlateMap(null);
                      setSelId(null);
                      setErr(null);
                      setTab("overview");
                    },
                  });
                }}
                className="px-3 py-1.5 text-[11px] rounded-sm flex items-center gap-1.5"
                style={{
                  background: "#fff",
                  color: "#797870",
                  border: "1px solid #e6e8e8",
                  fontWeight: 600,
                  fontFamily: '"Raleway", sans-serif',
                }}
                onMouseOver={(e) => {
                  e.currentTarget.style.borderColor = "#ed6e6c";
                  e.currentTarget.style.color = "#ed6e6c";
                }}
                onMouseOut={(e) => {
                  e.currentTarget.style.borderColor = "#e6e8e8";
                  e.currentTarget.style.color = "#797870";
                }}
              >
                <X className="w-3 h-3" />
                Clear session
              </button>
            )}
          </div>
          <div className="grid md:grid-cols-2 gap-4">
            <UploadCard
              label="contamination_events.tsv"
              hint="CroCoDeEL output — required"
              filename={events.length ? `${events.length} events loaded` : null}
              onFile={loadEvents}
              primary
              inputRef={eventFileRef}
              info={
                <>
                  <div style={{ fontWeight: 700, marginBottom: 4 }}>
                    CroCoDeEL output file (TSV)
                  </div>
                  Required columns:{" "}
                  <code style={{ fontFamily: "ui-monospace, monospace" }}>
                    source
                  </code>
                  ,{" "}
                  <code style={{ fontFamily: "ui-monospace, monospace" }}>
                    target
                  </code>
                  ,{" "}
                  <code style={{ fontFamily: "ui-monospace, monospace" }}>
                    rate
                  </code>
                  ,{" "}
                  <code style={{ fontFamily: "ui-monospace, monospace" }}>
                    probability
                  </code>
                  ,{" "}
                  <code style={{ fontFamily: "ui-monospace, monospace" }}>
                    contamination_specific_species
                  </code>
                  . An optional first comment line starting with{" "}
                  <code style={{ fontFamily: "ui-monospace, monospace" }}>#</code>{" "}
                  carries CroCoDeEL run parameters and is shown in the
                  Overview tab.
                </>
              }
              onDownload={
                rawEvents.length
                  ? () =>
                      downloadText(
                        eventsToTSV(rawEvents, runMetadata),
                        "contamination_events.tsv",
                      )
                  : undefined
              }
              onClear={
                rawEvents.length
                  ? () => {
                      setRawEvents([]);
                      setRunMetadata(null);
                      setSelId(null);
                    }
                  : undefined
              }
              confirmDialog={setBulkConfirm}
            />
            <UploadCard
              label="species_abundance.tsv"
              hint="Abundance table — enables scatterplots and assisted scoring"
              filename={
                ab
                  ? `${ab.samples.length} samples × ${ab.species.length} species`
                  : null
              }
              onFile={loadAbundance}
              inputRef={abFileRef}
              info={
                <>
                  <div style={{ fontWeight: 700, marginBottom: 4 }}>
                    Species × sample abundance matrix (TSV)
                  </div>
                  First column lists species names, every other column is a
                  sample. Values are normalized to relative abundances
                  (summing to 1 per sample) at parse time. Loading this file
                  unlocks scatterplots, assisted scoring criteria, and
                  inline mini-scatterplots in Guided validation.
                </>
              }
              onDownload={
                ab
                  ? () =>
                      downloadText(abundanceToTSV(ab), "species_abundance.tsv")
                  : undefined
              }
              onClear={ab ? () => setAb(null) : undefined}
              confirmDialog={setBulkConfirm}
            />
            <MetadataUploadCard
              metadata={metadata}
              setMetadata={setMetadata}
              setErr={setErr}
              confirmDialog={setBulkConfirm}
            />
            <PlateUploadCard
              plateMap={plateMap}
              setPlateMap={setPlateMap}
              setErr={setErr}
              confirmDialog={setBulkConfirm}
            />
          </div>
        </div>
        {err && (
          <div className="max-w-7xl mx-auto px-6 pb-4">
            <div
              className="flex items-center gap-2 text-sm px-3 py-2 rounded-sm"
              style={{
                background: "#fdeceb",
                border: "1px solid #ed6e6c",
                color: "#8a2422",
              }}
            >
              <AlertCircle className="w-4 h-4" />
              {err}
            </div>
          </div>
        )}
        {sampleMismatches && (
          <div className="max-w-7xl mx-auto px-6 pb-4">
            <div
              className="flex items-start gap-2 text-[13px] px-3 py-2 rounded-sm"
              style={{
                background: "#fff3cd",
                border: "1px solid #e3a100",
                color: "#6b4500",
              }}
            >
              <AlertCircle className="w-4 h-4 shrink-0 mt-0.5" />
              <div>
                <strong>Sample names in events don't all match the abundance table.</strong>{" "}
                {sampleMismatches.missingCount > 0 && (
                  <>
                    {sampleMismatches.missingCount} sample
                    {sampleMismatches.missingCount > 1 ? "s are" : " is"}{" "}
                    missing — scatterplots will show an error for those events.
                    First few:{" "}
                    <code style={{ fontFamily: "system-ui, monospace" }}>
                      {sampleMismatches.missing.join(", ")}
                      {sampleMismatches.missingCount > 10 ? " …" : ""}
                    </code>
                    .{" "}
                  </>
                )}
                {sampleMismatches.casediffCount > 0 && (
                  <>
                    {sampleMismatches.casediffCount} other
                    {sampleMismatches.casediffCount > 1 ? "s" : ""} differ only
                    by case/whitespace and are auto-matched.
                  </>
                )}
              </div>
            </div>
          </div>
        )}
      </section>

      {/* ==================== CONTENT ==================== */}
      <div className="max-w-7xl mx-auto px-6 py-5">
        <nav
          className="flex flex-wrap gap-0 mb-6"
          style={{ borderBottom: "2px solid #e6e8e8" }}
        >
            {[
              { id: "overview", label: "Overview", icon: BookOpen, requiresData: false },
              { id: "table", label: "Events table", icon: Droplets, requiresData: true },
              { id: "scatter", label: "Scatterplots", icon: ScatterIcon, requiresData: true },
              { id: "network", label: "Network", icon: GitBranch, requiresData: true },
              { id: "plate", label: "Plate map", icon: Grid3x3, requiresData: true },
              { id: "validate", label: "Guided validation", icon: ClipboardCheck, requiresData: true },
              { id: "export", label: "Export", icon: Download, requiresData: true },
              { id: "datasets", label: "Datasets", icon: Library, requiresData: false, secondary: true },
              { id: "learn", label: "Learn", icon: GraduationCap, requiresData: false, secondary: true, accent: "#423089" },
              { id: "help", label: "Help", icon: HelpCircle, requiresData: false, secondary: true },
            ].map((t, idx, arr) => {
              const Icon = t.icon;
              const active = tab === t.id;
              const disabled = t.requiresData && events.length === 0;
              // First "secondary" tab gets pushed to the right so all
              // secondary tabs (Learn, Help) sit visually apart from the
              // workflow tabs.
              const isFirstSecondary =
                t.secondary && (!arr[idx - 1] || !arr[idx - 1].secondary);
              const accent = t.accent || "#00a3a6";
              return (
                <button
                  key={t.id}
                  onClick={() => !disabled && setTab(t.id)}
                  disabled={disabled}
                  data-tutorial={`tab-${t.id}`}
                  title={
                    disabled
                      ? "Load contamination_events.tsv first"
                      : undefined
                  }
                  className="px-5 py-3 text-[13px] flex items-center gap-2"
                  style={{
                    marginLeft: isFirstSecondary ? "auto" : undefined,
                    borderBottom: active
                      ? `3px solid ${accent}`
                      : "3px solid transparent",
                    color: disabled
                      ? "#c4c0b3"
                      : active
                        ? "#275662"
                        : t.accent
                          ? t.accent
                          : "#797870",
                    fontWeight: active ? 700 : t.accent ? 600 : 500,
                    marginBottom: "-2px",
                    fontFamily: '"Raleway", sans-serif',
                    cursor: disabled ? "not-allowed" : "pointer",
                    opacity: disabled ? 0.5 : 1,
                  }}
                >
                  <Icon className={t.iconClass || "w-4 h-4"} />
                  {t.label}
                </button>
              );
            })}
          </nav>

          {(events.length > 0 || tab === "help" || tab === "overview" || tab === "learn" || tab === "datasets") && (
            <>
          {tab === "overview" && (
            <Overview
              counts={counts}
              events={events}
              hasAb={!!ab}
              metadata={metadata}
              plateMap={plateMap}
              runMetadata={runMetadata}
              onOpen={(id) => {
                setSelId(id);
                setTab("validate");
              }}
              onLoadDemo={loadDemo}
              demoLoading={demoLoading}
            />
          )}
          {tab === "table" && (
            <EventsTable
              events={filtered}
              total={events.length}
              filter={filter}
              setFilter={setFilter}
              sort={sort}
              setSort={setSort}
              metadata={metadata}
              plateMap={plateMap}
              runMetadata={runMetadata}
              onPick={(id) => {
                setSelId(id);
                setTab(ab ? "validate" : "scatter");
              }}
              setVerdict={setVerdict}
            />
          )}
          {tab === "scatter" && (
            <ScatterTab
              events={events}
              filtered={filtered}
              filter={filter}
              setFilter={setFilter}
              ab={ab}
              metadata={metadata}
              plateMap={plateMap}
              runMetadata={runMetadata}
              setVerdict={setVerdict}
              onPick={(id) => {
                setSelId(id);
                setTab("validate");
              }}
              onAddManualEvent={addManualEvent}
            />
          )}
          {tab === "network" && (
            <NetworkTab
              events={events}
              filtered={filtered}
              filter={filter}
              setFilter={setFilter}
              metadata={metadata}
              plateMap={plateMap}
              runMetadata={runMetadata}
              onPick={(id) => {
                setSelId(id);
                setTab("validate");
              }}
            />
          )}
          {tab === "plate" && (
            <PlateTab
              events={events}
              plateMap={plateMap}
              setPlateMap={setPlateMap}
              samples={allSamples}
              metadata={metadata}
              focusPlate={focusPlate}
              onPick={(id) => {
                setSelId(id);
                setTab("validate");
              }}
            />
          )}
          {tab === "validate" && (
            <ValidateTab
              events={events}
              selected={selected}
              onSelect={setSelId}
              scatter={scatter}
              diag={diag}
              above={above}
              missing={missing}
              autoScore={autoScore}
              hasAb={!!ab}
              ab={ab}
              setVerdict={setVerdict}
              setNote={setNote}
              metadata={metadata}
              plateMap={plateMap}
              bulkMarkSameSubjectAsFP={bulkMarkSameSubjectAsFP}
              bulkMarkTowardNCAsTP={bulkMarkTowardNCAsTP}
              bulkResetAllVerdicts={bulkResetAllVerdicts}
              bulkApplyToEvents={bulkApplyToEvents}
              onOpenPlate={(plateId) => {
                setFocusPlate(plateId || null);
                setTab("plate");
              }}
            />
          )}
          {tab === "export" && (
            <ExportTab
              counts={counts}
              onExportTSV={exportReport}
              onExportJSON={exportJSON}
              onExportHTML={exportHTMLReport}
            />
          )}
          {tab === "datasets" && (
            <DatasetsTab
              onLoadDataset={loadDataset}
              hasCurrentData={
                rawEvents.length > 0 || !!ab || !!metadata || !!plateMap
              }
            />
          )}
          {tab === "learn" && <LearnTab />}
          {tab === "help" && (
            <HelpTab onStartTour={startTutorial} />
          )}
            </>
          )}
        </div>

      {/* Discrete "Saved" indicator: appears bottom-right after each
          successful auto-save and fades out after a couple of seconds.
          Lets the user know the work is being persisted without
          interrupting the flow. */}
      <SavedPill timestamp={savedAt} />

      {/* First-visit welcome popup. Asks the user whether to take the
          guided tour or skip. Sets the tutorial-seen flag in either
          case so it doesn't show again. */}
      {welcomeOpen && (
        <TutorialWelcome
          onStart={() => {
            setWelcomeOpen(false);
            startTutorial();
          }}
          onSkip={() => {
            tutorialMarkSeen();
            setWelcomeOpen(false);
          }}
        />
      )}

      {/* Side-panel guided tour. Triggered from the welcome popup or
          from the "Restart guided tour" button in the Help tab. */}
      {tutorialOpen && (
        <TutorialPanel
          steps={tutorialSteps}
          onClose={() => setTutorialOpen(false)}
          onAction={handleTutorialAction}
          dataLoaded={rawEvents.length > 0}
          demoLoading={demoLoading}
        />
      )}

      {/* Centralised confirm/info modal — used for ALL confirmation
          prompts in the app (bulk validation actions, file removal,
          session reset). Replaces window.confirm which Chromium can
          suppress after rapid successive uses, and gives us a uniform
          look across the app. */}
      {bulkConfirm && (
        <div
          onClick={() => setBulkConfirm(null)}
          style={{
            position: "fixed",
            inset: 0,
            background: "rgba(39,86,98,0.5)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 1000,
            padding: 20,
          }}
        >
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              background: "#fff",
              borderRadius: 4,
              padding: "24px 28px",
              maxWidth: 520,
              width: "100%",
              boxShadow: "0 12px 32px rgba(0,0,0,0.2)",
              borderLeft: `4px solid ${bulkConfirm.destructive ? "#ed6e6c" : "#00a3a6"}`,
            }}
          >
            <h3
              style={{
                fontSize: 18,
                fontWeight: 700,
                color: "#275662",
                fontFamily: '"Raleway", sans-serif',
                marginBottom: 12,
              }}
            >
              {bulkConfirm.title}
            </h3>
            <p
              style={{
                fontSize: 13,
                color: "#5a5550",
                lineHeight: 1.6,
                whiteSpace: "pre-wrap",
                marginBottom: 20,
              }}
            >
              {bulkConfirm.body}
            </p>
            <div
              style={{
                display: "flex",
                gap: 10,
                justifyContent: "flex-end",
              }}
            >
              <button
                onClick={() => setBulkConfirm(null)}
                style={{
                  padding: "8px 16px",
                  fontSize: 12,
                  fontWeight: 600,
                  background: "#fff",
                  color: "#797870",
                  border: "1px solid #c4c0b3",
                  borderRadius: 3,
                  cursor: "pointer",
                  fontFamily: '"Raleway", sans-serif',
                }}
              >
                {bulkConfirm.kind === "confirm" ? "Cancel" : "Close"}
              </button>
              {bulkConfirm.kind === "confirm" && (
                <button
                  onClick={() => {
                    bulkConfirm.onConfirm?.();
                    setBulkConfirm(null);
                  }}
                  style={{
                    padding: "8px 16px",
                    fontSize: 12,
                    fontWeight: 700,
                    background: bulkConfirm.destructive ? "#ed6e6c" : "#00a3a6",
                    color: "#fff",
                    border: "none",
                    borderRadius: 3,
                    cursor: "pointer",
                    fontFamily: '"Raleway", sans-serif',
                    letterSpacing: "0.02em",
                  }}
                >
                  {bulkConfirm.confirmLabel || "Confirm"}
                </button>
              )}
            </div>
          </div>
        </div>
      )}

      {/* ==================== FOOTER ==================== */}
      <footer
        style={{
          background: "#fff",
          borderTop: "1px solid #e6e8e8",
          marginTop: 48,
        }}
      >
        <div className="max-w-7xl mx-auto px-6 py-8">
          <div className="flex flex-col items-center text-center gap-4">
            <div className="flex items-center justify-center gap-2 flex-wrap">
              <Chevron size={18} color="#00a3a6" />
              <span
                className="text-[13px] whitespace-nowrap"
                style={{
                  color: "#275662",
                  fontWeight: 600,
                  fontFamily: '"Raleway", sans-serif',
                }}
              >
                Institut National de Recherche pour l'Agriculture, l'Alimentation et l'Environnement (INRAE)
              </span>
            </div>
            <div className="flex items-center gap-6 mt-2">
              <RepubliqueFrancaise height={40} />
              <InraeLogo height={28} />
            </div>
            <div
              className="text-[11px] mt-4 max-w-2xl leading-relaxed"
              style={{ color: "#797870" }}
            >
              Interpretation aid for CroCoDeEL results. Cite: Goulet L. et al.,
              bioRxiv 2025,{" "}
              <a
                href="https://doi.org/10.1101/2025.01.15.633153"
                target="_blank"
                rel="noopener noreferrer"
                style={{
                  color: "#00a3a6",
                  textDecoration: "underline",
                }}
              >
                doi.org/10.1101/2025.01.15.633153
              </a>
              .
            </div>
            <div
              className="text-[11px] mt-1 italic"
              style={{ color: "#797870" }}
            >
              Created using Claude Opus 4.7, prompted by G. Gautreau.
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
}
